373	bool Opencore::Coredump(const char* filename) {
374	    pid_t child = fork();
375	    if (child == 0) {
376	        IgnoreHandler();
377	        signal(SIGALRM, Opencore::TimeoutHandle);
378	        alarm(getTimeout());
379	        DoCoredump(filename);
380	        Finish();
381	        _exit(0);
382	    } else {
383	        JNI_LOGI("Wait (%d) coredump", child);
384	        int status = 0;
385	        wait(&status);
386	    }
387	    return true;
